// src/components/ScriptForm.js
import React, { useState } from "react";
import {
  TextField,
  Button,
  Box,
  Typography,
  MenuItem,
  CircularProgress,
  Paper,
  Alert,
} from "@mui/material";

/**
 * fetchWithBackoff
 * - retries on network errors and 429/503 responses with exponential backoff
 * - returns the final fetch Response object (you still need to check res.ok)
 */
async function fetchWithBackoff(url, options = {}, retries = 4, baseDelay = 500) {
  for (let attempt = 0; attempt < retries; attempt++) {
    try {
      const res = await fetch(url, options);

      // If 429 or 503 -> retry (unless it's last attempt)
      if ((res.status === 429 || res.status === 503) && attempt < retries - 1) {
        const delay = baseDelay * Math.pow(2, attempt);
        console.warn(`Request returned ${res.status}. Retrying in ${delay} ms (attempt ${attempt + 1})`);
        await new Promise((r) => setTimeout(r, delay));
        continue; // retry
      }

      // If not a retryable status, return response (could be ok or other 4xx/5xx)
      return res;
    } catch (err) {
      // Network error or other failure - retry unless last attempt
      if (attempt < retries - 1) {
        const delay = baseDelay * Math.pow(2, attempt);
        console.warn(`Fetch failed: ${err.message}. Retrying in ${delay} ms (attempt ${attempt + 1})`);
        await new Promise((r) => setTimeout(r, delay));
        continue;
      }
      // Last attempt: rethrow
      throw err;
    }
  }

  // Should never reach here
  throw new Error("Exceeded retry attempts");
}

export default function ScriptForm() {
  const [topic, setTopic] = useState("");
  const [tone, setTone] = useState("Funny");
  const [loading, setLoading] = useState(false);
  const [retrying, setRetrying] = useState(false);
  const [script, setScript] = useState("");
  const [error, setError] = useState("");

  // Decide base URL: use env var if set, else same-origin (useful with CRA proxy)
  const base = (process.env.REACT_APP_API_URL || "").replace(/\/+$/, "");
  const endpoint = `${base}/api/generate`; // if base is "", this becomes "/api/generate"

  const handleGenerate = async () => {
    setLoading(true);
    setRetrying(false);
    setError("");
    setScript("");

    // Simple client-side guard
    if (!topic || !topic.trim()) {
      setError("Please enter a topic for the video.");
      setLoading(false);
      return;
    }

    const payload = { topic: topic.trim(), tone };

    try {
      // We'll interpret 429/503 as retryable inside fetchWithBackoff
      // Show a "retrying" indicator if retries happen (we detect by comparing attempts)
      let attempt = 0;
      const originalConsoleWarn = console.warn;
      // small hack: intercept console.warn to set retrying state when a retry occurs
      console.warn = (msg, ...args) => {
        if (typeof msg === "string" && msg.includes("Retrying in")) {
          setRetrying(true);
        }
        originalConsoleWarn(msg, ...args);
      };

      const res = await fetchWithBackoff(
        endpoint,
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload),
        },
        4, // retries
        600 // baseDelay in ms (slightly higher to reduce burst)
      );

      // restore console.warn
      console.warn = originalConsoleWarn;

      if (!res) throw new Error("No response from server.");

      // Handle specific status codes
      if (res.status === 429) {
        throw new Error("Rate limit reached. Please wait a moment and try again.");
      }
      if (!res.ok) {
        // Try to read server JSON error message
        let data;
        try {
          data = await res.json();
        } catch {
          // not json
        }
        const msg = (data && data.error) || `Request failed with status ${res.status}`;
        throw new Error(msg);
      }

      const data = await res.json();
      if (!data || !data.script) {
        throw new Error("No script returned. Check server logs.");
      }

      setScript(data.script);
    } catch (err) {
      console.error("Generate error:", err);
      setError(err.message || "An unexpected error occurred.");
    } finally {
      setLoading(false);
      // remove any retrying indicator after finish
      setTimeout(() => setRetrying(false), 500);
    }
  };

  return (
    <Box sx={{ mt: 4 }}>
      <TextField
        fullWidth
        label="Enter video topic"
        value={topic}
        onChange={(e) => setTopic(e.target.value)}
        margin="normal"
        placeholder="e.g., 5 editing tricks for YouTube beginners"
      />

      <TextField
        select
        fullWidth
        label="Select Tone"
        value={tone}
        onChange={(e) => setTone(e.target.value)}
        margin="normal"
      >
        <MenuItem value="Funny">Funny</MenuItem>
        <MenuItem value="Serious">Serious</MenuItem>
        <MenuItem value="Inspirational">Inspirational</MenuItem>
        <MenuItem value="Edgy">Edgy</MenuItem>
        <MenuItem value="Neutral">Neutral</MenuItem>
      </TextField>

      <Box sx={{ display: "flex", gap: 2, alignItems: "center", mt: 2 }}>
        <Button
          variant="contained"
          onClick={handleGenerate}
          disabled={loading || !topic.trim()}
          startIcon={loading ? <CircularProgress size={18} /> : null}
        >
          {loading ? "Generating..." : "Generate Script"}
        </Button>

        {retrying && (
          <Typography variant="body2" color="text.secondary">
            Retrying due to rate limits... please wait.
          </Typography>
        )}
      </Box>

      {error && (
        <Alert severity="error" sx={{ mt: 3 }}>
          {error}
        </Alert>
      )}

      {script && (
        <Paper sx={{ mt: 4, p: 3, whiteSpace: "pre-wrap", bgcolor: "#f7f7f7" }}>
          <Typography variant="h6" gutterBottom>
            Generated Script
          </Typography>
          <Typography variant="body1" sx={{ whiteSpace: "pre-wrap" }}>
            {script}
          </Typography>
        </Paper>
      )}

      <Box sx={{ mt: 3 }}>
        <Typography variant="caption" color="text.secondary">
          Note: For development, ensure your backend is running at{" "}
          <strong>{base || "/ (same-origin via proxy)"}</strong>. In production, set{" "}
          <code>REACT_APP_API_URL</code> to your server URL.
        </Typography>
      </Box>
    </Box>
  );
}
